const raw = $input.first().json['Leads'] || '';
return raw.split('\n').map(l => l.trim()).filter(l => l)
  .map(line => {
    const parts = line.split(',');
    const full_name    = (parts[0] || '').trim();
    const company_name = (parts[1] || '').trim();
    return { json: { full_name, company_name, search_query: `${full_name} ${company_name}`.trim() } };
  });

const response     = $input.first().json;
const data         = response.result || response;
const lead         = $('One Lead at a Time').first().json;
const linkedin_url = $('Linkfinder — Find LinkedIn URL').first().json.result || '';

const currentYear  = new Date().getFullYear();
const firstYear    = parseInt(data.firstRoleYear || 0);

return [{ json: {
  input_name:       lead.full_name     || '',
  input_company:    lead.company_name  || '',
  name:             data.name          || lead.full_name || '',
  job_title:        data.jobTitle       || data.job_title || '',
  company:          data.company        || lead.company_name || '',
  headline:         data.headline       || '',
  location:         data.location       || '',
  country:          data.country        || '',
  industry:         data.industry       || '',
  email:            data.email          || '',
  mobile:           data.mobileNumber   || '',
  connections:      data.connections    || '',
  is_employed:      data.isCurrentlyEmployed != null ? String(data.isCurrentlyEmployed) : '',
  years_experience: firstYear ? String(currentYear - firstYear) : '',
  linkedin_url
}}];
